fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();
    if n == 0 {
        return vec![];
    }

    let sorted_nums: Vec<i64> = {
        let mut tmp = nums.clone();
        tmp.sort();
        tmp.dedup();
        tmp
    };
    let comp_map: HashMap<i64, usize> = sorted_nums
        .iter()
        .enumerate()
        .map(|(i, &x)| (x, i))
        .collect();
    let unique_count = sorted_nums.len();

    let mut buckets: Vec<BTreeSet<usize>> = vec![BTreeSet::new(); n + 1];
    let mut freq_arr: Vec<usize> = vec![0; unique_count];
    let mut max_freq: usize = 0;

    let block_size = (n as f64).sqrt().ceil() as usize;
    let mut sorted_queries: Vec<(usize, usize, usize, usize)> = vec![];
    for (idx, q) in queries.iter().enumerate() {
        let l = q[0] as usize;
        let r = q[1] as usize;
        let threshold = q[2] as usize;
        sorted_queries.push((l, r, threshold, idx));
    }
    sorted_queries.sort_by(|a, b| {
        let block_a = a.0 / block_size;
        let block_b = b.0 / block_size;
        if block_a != block_b {
            block_a.cmp(&block_b)
        } else {
            if block_a % 2 == 0 {
                a.1.cmp(&b.1)
            } else {
                b.1.cmp(&a.1)
            }
        }
    });

    let mut ans: Vec<i64> = vec![-1; queries.len()];
    let mut l_curr: i32 = 0;
    let mut r_curr: i32 = -1;

    for &(l, r, threshold, idx) in sorted_queries.iter() {
        let l = l as i32;
        let r = r as i32;

        while r_curr < r {
            r_curr += 1;
            let pos = r_curr as usize;
            let x = nums[pos];
            let comp = *comp_map.get(&x).unwrap();
            let old_freq = freq_arr[comp];
            if old_freq > 0 {
                buckets[old_freq].remove(&comp);
            }
            let new_freq = old_freq + 1;
            freq_arr[comp] = new_freq;
            buckets[new_freq].insert(comp);
            if new_freq > max_freq {
                max_freq = new_freq;
            }
        }

        while r_curr > r {
            let pos = r_curr as usize;
            let x = nums[pos];
            let comp = *comp_map.get(&x).unwrap();
            let old_freq = freq_arr[comp];
            buckets[old_freq].remove(&comp);
            let new_freq = old_freq - 1;
            freq_arr[comp] = new_freq;
            if new_freq > 0 {
                buckets[new_freq].insert(comp);
            }
            if old_freq == max_freq && buckets[old_freq].is_empty() {
                max_freq = old_freq - 1;
            }
            r_curr -= 1;
        }

        while l_curr < l {
            let pos = l_curr as usize;
            let x = nums[pos];
            let comp = *comp_map.get(&x).unwrap();
            let old_freq = freq_arr[comp];
            buckets[old_freq].remove(&comp);
            let new_freq = old_freq - 1;
            freq_arr[comp] = new_freq;
            if new_freq > 0 {
                buckets[new_freq].insert(comp);
            }
            if old_freq == max_freq && buckets[old_freq].is_empty() {
                max_freq = old_freq - 1;
            }
            l_curr += 1;
        }

        while l_curr > l {
            l_curr -= 1;
            let pos = l_curr as usize;
            let x = nums[pos];
            let comp = *comp_map.get(&x).unwrap();
            let old_freq = freq_arr[comp];
            if old_freq > 0 {
                buckets[old_freq].remove(&comp);
            }
            let new_freq = old_freq + 1;
            freq_arr[comp] = new_freq;
            buckets[new_freq].insert(comp);
            if new_freq > max_freq {
                max_freq = new_freq;
            }
        }

        if max_freq >= threshold && max_freq > 0 {
            let comp_candidate = *buckets[max_freq].iter().next().unwrap();
            ans[idx] = sorted_nums[comp_candidate];
        } else {
            ans[idx] = -1;
        }
    }

    ans
}
