use std::collections::{BTreeSet, HashMap};

struct MosState {
    buckets: Vec<BTreeSet<i64>>,
    freq_map: HashMap<i64, i32>,
    current_max_freq: i32,
}

impl MosState {
    fn new(max_freq: usize) -> Self {
        let buckets = vec![BTreeSet::new(); max_freq + 1];
        Self {
            buckets,
            freq_map: HashMap::new(),
            current_max_freq: 0,
        }
    }

    fn add(&mut self, x: i64) {
        let count = self.freq_map.entry(x).or_insert(0);
        let old_freq = *count;
        if old_freq > 0 {
            self.buckets[old_freq as usize].remove(&x);
        }
        *count += 1;
        let new_freq = old_freq + 1;
        if (new_freq as usize) < self.buckets.len() {
            self.buckets[new_freq as usize].insert(x);
        }
        if new_freq > self.current_max_freq {
            self.current_max_freq = new_freq;
        }
    }

    fn remove(&mut self, x: i64) {
        let present = if let Some(count) = self.freq_map.get_mut(&x) {
            let old_freq = *count;
            self.buckets[old_freq as usize].remove(&x);
            if old_freq == self.current_max_freq && self.buckets[old_freq as usize].is_empty() {
                self.current_max_freq = old_freq - 1;
            }
            *count -= 1;
            let new_freq = old_freq - 1;
            if new_freq > 0 {
                self.buckets[new_freq as usize].insert(x);
                true
            } else {
                false
            }
        } else {
            false
        };
        if !present {
            self.freq_map.remove(&x);
        }
    }

    fn answer_query(&self, threshold: i64) -> i64 {
        if self.current_max_freq as i64 >= threshold {
            if let Some(&min_val) = self.buckets[self.current_max_freq as usize].iter().next() {
                min_val
            } else {
                -1
            }
        } else {
            -1
        }
    }
}

